# Method 2: Manual rate limiting with in-memory store
import time
from collections import defaultdict
from flask import Flask, request, jsonify
from functools import wraps

rate_limit_store = defaultdict(list)

def rate_limit(max_requests, window_seconds):
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            client_ip = request.remote_addr
            now = time.time()
            key = f'{client_ip}:{f.__name__}'

            # Remove old entries outside the window
            rate_limit_store[key] = [
                t for t in rate_limit_store[key]
                if t > now - window_seconds
            ]

            if len(rate_limit_store[key]) >= max_requests:
                retry_after = int(window_seconds - (now - rate_limit_store[key][0]))
                response = jsonify({
                    'error': 'Rate limit exceeded',
                    'retry_after': retry_after
                })
                response.status_code = 429
                response.headers['Retry-After'] = str(retry_after)
                response.headers['X-RateLimit-Limit'] = str(max_requests)
                response.headers['X-RateLimit-Remaining'] = '0'
                return response

            rate_limit_store[key].append(now)

            response = f(*args, **kwargs)
            remaining = max_requests - len(rate_limit_store[key])
            response.headers['X-RateLimit-Limit'] = str(max_requests)
            response.headers['X-RateLimit-Remaining'] = str(remaining)
            return response
        return wrapped
    return decorator

